package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.IdDatumKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenElementenBoekingKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenElementenKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdArtikelKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ArtikelLoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Inhouding;
import be.schaubroeck.lpb.tools.MaandTotaal1;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RekenElement;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.OpslaanNulResultaten;
import be.schaubroeck.lpb.tools.util.ReflectionUtil;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.ListMultimap;
import org.joda.time.LocalDateTime;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.TreeSet;

public class MaandTotaalBeheer extends MaandTotaalBeheerBasis {
    private final RekenElementBeheer rekenElementBeheer = new RekenElementBeheer();

    public List<MaandTotaal1> maakMaandTotaal(
            Set<Opdracht> opdrachten, RekenTijd rekenTijd, ArtikelLoonElementManager manager, List<MaandTotaal1> bestaanden,
            Map<Integer, LocalDateInterval> opdrachtIdToMaandTotaalPeriode, ListMultimap<IdDatumKey, NlpPrestatie> opdrachtIdToPrestatiesMap,
            OpslaanNulResultaten strategieNulResultaten, LoonCodeManager loonCodeManager, ConstantManager constantManager) {
        Integer sNummer = 0;
        boolean belastbaarVrijwilligeBrandweer = RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(opdrachten);
        ListMultimap<Integer, MaandTotaal1> opdrachtNrToBestaanden = mapOpdrachtNrToBestaanden(bestaanden);
        Map<Integer, Boolean> opdrachtNrToNulResultaat =
                mapOpdrachtNrToNullResultaat(opdrachten, strategieNulResultaten, opdrachtNrToBestaanden, opdrachtIdToPrestatiesMap, rekenTijd);
        List<MaandTotaal1> maandTotalen = new ArrayList<>();
        Constant afwijkendeVrwPerMaandCst = constantManager.getActualConstant(Konstanten.CST_HVZ_AFWIJKENDE_VERW_PER_MAAND, rekenTijd);
        boolean afwijkendeVrwPerMaand = afwijkendeVrwPerMaandCst.getBoolean();
        for (Opdracht opdracht : opdrachten) {
            List<MaandTotaal1> opdrachtBestaanden = opdrachtNrToBestaanden.get(opdracht.getOpdrachtnr());
            ListMultimap<RekenHoofdArtikelKey, MaandTotaal1> mapRekenHoofdKeyToMaandTotalen =
                    mapRekenHoofdKeyToMaandTotalen(opdracht, opdrachtBestaanden);

            Set<RekenHoofdArtikelKey> rekenHoofdMtKeys = new TreeSet<>(mapRekenHoofdKeyToMaandTotalen.keySet());
            Set<RekenHoofdArtikelKey> rekenHoofdHuidigeKeys = new TreeSet<>(getRekenHoofdArtikelKeyHuidigeOpdracht(manager, opdracht, rekenTijd, afwijkendeVrwPerMaand));
            Set<RekenHoofdArtikelKey> diffKeys = new TreeSet<>(rekenHoofdHuidigeKeys);
            diffKeys.removeAll(rekenHoofdMtKeys);

            Set<RekenHoofdArtikelKey> rekenHoofdKeys = new TreeSet<>();
            rekenHoofdKeys.addAll(rekenHoofdMtKeys);
            rekenHoofdKeys.addAll(rekenHoofdHuidigeKeys);
            for (RekenHoofdArtikelKey key : rekenHoofdKeys) {
                List<MaandTotaal1> opdrachtBestaandenPerKey = mapRekenHoofdKeyToMaandTotalen.get(key);
                ListMultimap<RekenElementenBoekingKey, RekenElement> opdrachtNrLooncodeToRekenElementen =
                        mapOpdrachtNrLooncodeToRekenElementen(opdrachtBestaandenPerKey);
                ListMultimap<RekenElementenKey, Inhouding> opdrachtNrLooncodeToInhoudingen =
                        mapOpdrachtNrLooncodeToInhoudingen(opdrachtBestaandenPerKey);

                MaandTotaal1 bestaandeSom = MaandTotaalUtil.maakGesommeerdMaandtotaal(opdrachtBestaandenPerKey);

                boolean vorigKwartaal = bepaalOpdrachtIsInOpzegOpEersteDagKwartaal(opdracht, key);
                LocalDateInterval maandTotaalPeriode = opdrachtIdToMaandTotaalPeriode.get(opdracht.getId());
                MaandTotaal1 maandTotaal1 = maakMaandTotaal1PO(opdracht, key, rekenTijd, vorigKwartaal, maandTotaalPeriode, sNummer);
                ReflectionUtil.initialiseerMoneyVelden(maandTotaal1);
                ReflectionUtil.initialiseerMoneyVelden(maandTotaal1.getMaandTotaal2());
                ReflectionUtil.initialiseerMoneyVelden(maandTotaal1.getMaandTotaal3());

                boolean bv18Exists = bestaandeSom.getBedrijfsvoorheffingZiv().signum() != 0;
                nieuweResultatenBoeken(key, manager, maandTotaal1, rekenTijd, belastbaarVrijwilligeBrandweer, bv18Exists);
                ReflectionUtil.substractMoneyFields(maandTotaal1, bestaandeSom);
                ReflectionUtil.substractMoneyFields(maandTotaal1.getMaandTotaal2(), bestaandeSom.getMaandTotaal2());
                ReflectionUtil.substractMoneyFields(maandTotaal1.getMaandTotaal3(), bestaandeSom.getMaandTotaal3());
                fixTeBetalenTeVorderen(maandTotaal1);
                vormNietGerekend(maandTotaal1);

                boolean nulResultaat = opdrachtNrToNulResultaat.get(opdracht.getOpdrachtnr());

                boolean nulMaandtotaal = maandTotaal1.isZeroMaandtotaal();
                rekenElementBeheer.vormRekenElementen(opdracht, key, manager, rekenTijd, maandTotaal1, opdrachtNrLooncodeToRekenElementen, maandTotaalPeriode,
                        nulResultaat && nulMaandtotaal, loonCodeManager, constantManager);
                vormInhoudingen(key, opdracht, manager, maandTotaal1, opdrachtNrLooncodeToInhoudingen);

                //De bedoeling hier is om te verzekeren dat als er een rekenhoofd/artikelhoofd is, dat er dan ook een mt is ook al is die zero
                boolean mirrorRekenHoofd = diffKeys.contains(key);

                if (!nulMaandtotaal || nulResultaat || !maandTotaal1.getRekenElementen().isEmpty() || mirrorRekenHoofd) {
                    maandTotalen.add(maandTotaal1);
                }
            }
        }
        if (opdrachtNrToNulResultaat.values().stream().reduce(false, Boolean::logicalOr)) {
            maandTotalen = cleanNulResultaten(maandTotalen);
        }

        return maandTotalen;
    }

    private static Map<Integer, Boolean> mapOpdrachtNrToNullResultaat(
            Set<Opdracht> opdrachten, OpslaanNulResultaten strategieNulResultaten,
            ListMultimap<Integer, MaandTotaal1> opdrachtNrToBestaanden, ListMultimap<IdDatumKey, NlpPrestatie> opdrachtIdToPrestatiesMap,
            RekenTijd rekenTijd) {
        Map<Integer, Boolean> opdrachtIdToNulResultaat = new HashMap<>();
        for (Opdracht opdracht : opdrachten) {
            List<NlpPrestatie> prestaties = opdrachtIdToPrestatiesMap.get(new IdDatumKey(opdracht.getId(), rekenTijd.eindDatum));
            opdrachtIdToNulResultaat.put(opdracht.getOpdrachtnr(),
                    beslissingNulResultaat(opdracht.getOpdrachtnr(), strategieNulResultaten, opdrachtNrToBestaanden, prestaties));
        }
        return opdrachtIdToNulResultaat;
    }

    private static boolean beslissingNulResultaat(
            Integer opdrachtNr, OpslaanNulResultaten strategieNulResultaten,
            ListMultimap<Integer, MaandTotaal1> opdrachtNrToBestaanden, List<NlpPrestatie> prestaties) {
        List<MaandTotaal1> bestaanden = opdrachtNrToBestaanden.get(opdrachtNr);
        boolean nulResultaat;
        if (strategieNulResultaten == OpslaanNulResultaten.LEGE_RESULTATEN_OPSLAAN) {
            nulResultaat = !prestaties.isEmpty() && bestaanden.isEmpty();
        } else if (strategieNulResultaten == OpslaanNulResultaten.WIJZIGING_KALENDER) {
            nulResultaat = versePrestatiesAanwezig(bestaanden, prestaties);
        } else {
            nulResultaat = false;
        }
        return nulResultaat;
    }

    private static boolean versePrestatiesAanwezig(List<MaandTotaal1> bestaandeResultaten, List<NlpPrestatie> prestaties) {
        LocalDateTime recentsteBerekening =
                bestaandeResultaten.stream().map(MaandTotaal1::getRekenTijdstip).max(LocalDateTime::compareTo).orElse(TimeTools.getMinimumTijdstip());
        LocalDateTime recentstePrestatie =
                prestaties.stream().map(NlpPrestatie::getIngaveTijdstip).max(LocalDateTime::compareTo).orElse(TimeTools.getMinimumTijdstip());

        return recentsteBerekening.isBefore(recentstePrestatie);
    }
}
